import java.io.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userName = reader.readLine();

            // Sanitize and escape user input before displaying it
            String sanitizedUserName = Encode.forHtml(userName);

            System.out.println("Hello, " + sanitizedUserName + "! Welcome to our website.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
